INSERT INTO public.medications VALUES ('43c3ddc3-00ee-4e00-8818-2be251f161f7', 'Advil', 'Ibuprofen', '200 mg', 'tablet', 'Take 1 tablet every 6-8 hours with food as needed for pain or fever.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('7ce52757-c5d3-47e1-b263-2c8a39a77fe0', 'Tylenol', 'Acetaminophen', '500 mg', 'tablet', 'Take 1 tablet every 4-6 hours as needed for pain or fever.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('4cc75ad8-6561-40a6-8a30-46fbb20b83b0', 'Lipitor', 'Atorvastatin', '20 mg', 'tablet', 'Take once daily to help lower cholesterol and reduce cardiovascular risk.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('870b6927-663b-4bcd-9f23-caddf533f6a9', 'Zoloft', 'Sertraline', '50 mg', 'tablet', 'Take once daily at the same time each day for treatment of depression or anxiety.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('6db94ed4-0677-45fc-81e4-84ad124b4330', 'Amoxil', 'Amoxicillin', '500 mg', 'capsule', 'Take every 8-12 hours as prescribed and finish the entire course of antibiotics.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('4cac571d-f55f-4352-a195-c6cb2bd035cc', 'Glucophage', 'Metformin', '500 mg', 'tablet', 'Take with meals to help control blood sugar in patients with type 2 diabetes.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('9f0df488-d0b9-4edb-bb77-3e1e6793dffe', 'Synthroid', 'Levothyroxine', '75 mg', 'tablet', 'Take once daily on an empty stomach 30-60 minutes before breakfast for thyroid hormone replacement.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('4e9f564a-68cc-4896-a550-89d673aecdd0', 'Prilosec', 'Omeprazole', '20 mg', 'capsule', 'Take once daily before a meal to reduce stomach acid and treat reflux.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('132a335f-277c-4bef-9371-4d607a3e0e71', 'Norvasc', 'Amlodipine', '5 mg', 'tablet', 'Take once daily to help control high blood pressure.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
INSERT INTO public.medications VALUES ('838ae497-7c18-468e-89fb-d82821a004c5', 'Ventolin', 'Albuterol', '90 mg', 'inhaler', 'Inhale 1-2 puffs every 4-6 hours as needed for relief of bronchospasm or shortness of breath.', '784c03c7-9bd6-4740-a559-9482556c5c36', '2026-03-17 00:09:08.493099');
